from flask import Flask, request, jsonify
import redis
import re
from functools import wraps

app = Flask(__name__)

# Secure command allowlist
ALLOWED_COMMANDS = {
    'GET', 'SET', 'DEL', 'EXISTS', 'TTL', 'KEYS', 'SCAN', 'INFO',
    'FLUSHDB', 'FLUSHALL', 'DBSIZE', 'PING', 'SELECT', 'CONFIG'
}

# Redis connection
redis_client = redis.Redis(host='localhost', port=6379, db=0, decode_responses=True)

def validate_command(command):
    """Validate command against allowlist"""
    if not command:
        return False
    command = command.upper().strip()
    return command in ALLOWED_COMMANDS

def secure_input(func):
    """Decorator to validate input"""
    @wraps(func)
    def wrapper(*args, **kwargs):
        command = request.args.get('command', '').strip()
        if not validate_command(command):
            return jsonify({'error': 'Invalid command'}), 400
        return func(*args, **kwargs)
    return wrapper

@app.route('/admin/redis', methods=['GET'])
@secure_input
def execute_redis_command():
    try:
        command = request.args.get('command', '').strip().upper()
        args = request.args.getlist('args')
        
        # Validate command
        if not validate_command(command):
            return jsonify({'error': 'Command not allowed'}), 400
            
        # Execute command securely
        result = redis_client.execute_command(command, *args)
        
        return jsonify({'result': result})
        
    except redis.exceptions.RedisError as e:
        return jsonify({'error': str(e)}), 500
    except Exception as e:
        return jsonify({'error': 'Internal server error'}), 500

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000, debug=False)